DB["<HTML>\n<BODY>\n<H1 align=\"center\">The Diary of High General Abbendis</H1>\n<BR/>\n<IMG src=\"Interface\\FlavorImages\\ScarletCrusadeLogo\"/>\n</BODY>\n</HTML>\n"]="<HTML>\n<BODY>\n<H1 align=\"center\">Journal du grand général Abbendis</H1>\n<BR/>\n<IMG src=\"Interface\\FlavorImages\\ScarletCrusadeLogo\"/>\n</BODY>\n</HTML>"
DB["<HTML>\n<BODY>\n<H1 align=\"center\">WANTED: HEMET NESINGWARY</H1>\n<H1 align=\"center\">FOR CRIMES AGAINST NATURE!</H1>\n<BR/>\n<IMG src=\"Interface\\Pictures\\obj_nesingwary_256\" align=\"center\"/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<H1 align=\"center\">Artist's rendition of \"The Extinctionator\" in his natural habitat: the burning hellfire of the underworld.</H1>\n<BR/>\n<H1 align=\"left\">Last Wildlife Holocaust Location: Nagrand, Outland</H1>\n<BR/>\n<H1 align=\"left\">Also Known As: The Great Game Hunter, The Butcher of Badlands, The Stranglethorn Ripper, Old Man Death, Hemet, Nessie, Ol' Dirty, Ol' Dirty D, Father of the Bounty, The Extinctionator</H1>\n<BR/>\n</BODY>\n</HTML>\n"]="<HTML>\n<BODY>\n<H1 align=\"center\">AVIS DE RECHERCHE : HEMET NESINGWARY</H1>\n<H1 align=\"center\">POUR CRIMES CONTRE LA NATURE !</H1>\n<BR/>\n<IMG src=\"Interface\\Pictures\\obj_nesingwary_256\" align=\"center\"/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<BR/>\n<H1 align=\"center\">Interprétation de l'artiste de « l'Extinctionator » dans son habitat naturel : les flammes infernales du monde souterrain.</H1>\n<BR/>\n<H1 align=\"left\">Localisation du dernier holocauste de vie sauvage : Nagrand, Outreterre</H1>\n<BR/>\n<H1 align=\"left\">Également appelé : le Chasseur de grands fauves, le Boucher des Terres ingrates, l'Éventreur de Strangleronce, le Vieux faucheur, Hemet, Nessie, Vieux salopard, le Donneur de primes, Extinctionator.</H1>\n<BR/>\n</BODY>\n</HTML>"
DB["<HTML>\n<BODY>\n<H1>Horde Conscription Registration</H1>\n<BR></BR>\n<P>This person has demonstrated incredible feats of strength and skill in the name of the Horde. They should immediately be assigned to work in the Crossroads.</P>\n<BR></BR>\n<BR></BR>\n<P>Respectfully yours:\n<BR></BR>- Kargal Battlescar</P>\n<BR></BR>\n<BR></BR>\n<BR></BR>\n<P>Looks good to me.<BR></BR>\n- Takrin Pathseeker</P>\n</BODY>\n</HTML>"]="<HTML>\n<BODY>\n<H1 align=\"center\">Registre de conscription de la Horde</H1>\n<BR/>\n<P>Cette personne a montré de grands talents au service de la Horde. Il faut immédiatement l'affecter à la Croisée.</P>\n<BR/><BR/>\n<P>Respectueusement :<BR/>\n- Kargal Balafre-glorieuse</P>\n<BR/><BR/>\n<P>Ça m'a l'air parfait.<BR/>\n- Takrin Cherchevoie</P>\n</BODY>\n</HTML>"
